91	@layer base {
92	  html {
93	    font-size: 17px; /* Global +1px bump — all rem values scale up proportionally */
94	  }
95	
96	  * {
97	    @apply border-border;
98	  }
99	
100	  body {
101	    @apply bg-background text-foreground;
102	    font-family: 'Poppins', sans-serif;
103	    -webkit-font-smoothing: antialiased;
104	    -moz-osx-font-smoothing: grayscale;
105	    line-height: 1.65;
106	    letter-spacing: -0.01em;
107	  }
108	
109	  h1, h2, h3, h4, h5, h6 {
110	    font-family: 'Vollkorn', serif;
111	    font-weight: 700;
112	    letter-spacing: -0.025em; /* Tight editorial tracking — Apple/Stripe style */
113	    line-height: 1.15;
