115	
116	  /* Apple-style button press — subtle scale down on active */
117	  button, [role="button"], a[class*="btn"], [data-state] {
118	    transition: transform 0.18s cubic-bezier(0.25, 0.46, 0.45, 0.94), 
119	                opacity 0.18s ease,
