135	@layer utilities {
136	  /* ============ Premium Apple/Nike-Level Transitions ============ */
137	  
138	  /* Base transition for all interactive elements */
139	  .transition-premium {
140	    transition: all 0.4s cubic-bezier(0.32, 0.72, 0, 1);
141	  }
142	  
143	  /* Subtle scale on hover - premium feel */
144	  .hover-scale {
145	    transition: transform 0.4s cubic-bezier(0.32, 0.72, 0, 1);
146	  }
147	  
148	  .hover-scale:hover {
149	    transform: scale(1.015);
150	  }
151	  
152	  /* Elegant lift effect */
153	  .hover-lift {
154	    transition: all 0.4s cubic-bezier(0.32, 0.72, 0, 1);
155	  }
156	  
157	  .hover-lift:hover {
158	    transform: translateY(-2px);
159	    box-shadow: 0 8px 24px -8px rgba(0, 0, 0, 0.12);
160	  }
161	  
162	  /* Soft glow effect */
163	  .hover-glow {
164	    transition: all 0.5s cubic-bezier(0.32, 0.72, 0, 1);
165	  }
166	  
167	  .hover-glow:hover {
168	    box-shadow: 0 0 24px rgba(211, 103, 37, 0.25);
169	  }
170	
171	  /* Premium card interaction */
172	  .card-interactive {
173	    transition: all 0.4s cubic-bezier(0.32, 0.72, 0, 1);
174	  }
175	  
176	  .card-interactive:hover {
177	    transform: translateY(-2px);
178	    box-shadow: 0 12px 32px -12px rgba(0, 0, 0, 0.15);
179	  }
180	  
181	  .card-interactive:active {
182	    transform: translateY(0) scale(0.99);
183	  }
184	
185	  /* Icon pulse on hover */
186	  .icon-hover {
187	    transition: all 0.3s cubic-bezier(0.32, 0.72, 0, 1);
188	  }
189	  
190	  .icon-hover:hover {
191	    transform: scale(1.1);
192	  }
193	
194	  /* Bronze Underline Animation */
195	  .bronze-underline {
196	    position: relative;
197	  }
198	  
199	  .bronze-underline::after {
200	    content: '';
201	    position: absolute;
202	    width: 100%;
203	    height: 2px;
204	    bottom: -2px;
205	    left: 0;
206	    background: hsl(var(--bronze));
207	    transform: scaleX(0);
208	    transform-origin: bottom right;
209	    transition: transform 0.4s cubic-bezier(0.32, 0.72, 0, 1);
210	  }
211	  
212	  .bronze-underline:hover::after {
213	    transform: scaleX(1);
214	    transform-origin: bottom left;
215	  }
216	  
217	  /* Gradient Text */
218	  .text-gradient-bronze {
219	    background: linear-gradient(135deg, hsl(var(--bronze)), hsl(var(--bronze-light)));
220	    -webkit-background-clip: text;
221	    -webkit-text-fill-color: transparent;
222	    background-clip: text;
223	  }
224	  
225	  /* Shimmer Effect */
226	  .shimmer {
227	    background: linear-gradient(
228	      90deg,
229	      transparent 0%,
230	      rgba(211, 103, 37, 0.08) 50%,
231	      transparent 100%
232	    );
233	    background-size: 1000px 100%;
234	    animation: shimmer 3s linear infinite;
235	  }
236	  
237	  /* ============ Animation Delays ============ */
238	  .stagger-1 { animation-delay: 0.05s; }
239	  .stagger-2 { animation-delay: 0.1s; }
240	  .stagger-3 { animation-delay: 0.15s; }
241	  .stagger-4 { animation-delay: 0.2s; }
242	  .stagger-5 { animation-delay: 0.25s; }
243	  .stagger-6 { animation-delay: 0.3s; }
244	  .stagger-7 { animation-delay: 0.35s; }
245	  .stagger-8 { animation-delay: 0.4s; }
246	  
247	  /* Fill mode for staggered animations */
248	  .animate-stagger {
249	    animation-fill-mode: both;
250	  }
251	  
252	  /* ============ Scrolling Gallery ============ */
253	  @keyframes scroll-left {
254	    0% {
255	      transform: translateX(0);
256	    }
257	    100% {
258	      transform: translateX(-33.333%);
259	    }
260	  }
261	
262	  .animate-scroll-left {
263	    animation: scroll-left 28s linear infinite;
264	  }
265	
266	  .animate-scroll-left:hover {
267	    animation-play-state: paused;
268	  }
269	
270	  /* ============ Page Transitions ============ */
271	  .page-enter {
272	    opacity: 0;
273	    transform: translateY(12px);
274	  }
275	  
276	  .page-enter-active {
277	    opacity: 1;
278	    transform: translateY(0);
279	    transition: opacity 0.5s cubic-bezier(0.32, 0.72, 0, 1), 
280	                transform 0.5s cubic-bezier(0.32, 0.72, 0, 1);
