282	
283	  /* ============ Focus States ============ */
284	  .focus-ring {
285	    transition: box-shadow 0.2s cubic-bezier(0.32, 0.72, 0, 1);
286	  }
287	  
288	  .focus-ring:focus-visible {
289	    outline: none;
290	    box-shadow: 0 0 0 2px hsl(var(--background)), 0 0 0 4px hsl(var(--bronze) / 0.5);
291	  }
292	
293	  /* ============ Smooth Scroll Behavior ============ */
294	  @media (prefers-reduced-motion: no-preference) {
295	    html {
296	      scroll-behavior: smooth;
297	    }
298	  }
299	
300	  /* ============ Loading States ============ */
301	  .skeleton-loading {
302	    background: linear-gradient(
303	      90deg,
304	      hsl(var(--muted)) 0%,
305	      hsl(var(--muted-foreground) / 0.1) 50%,
306	      hsl(var(--muted)) 100%
