331	  }
332	  }
333	
334	  /* ============ Premium Card Hover ============ */
335	  .card-hover {
336	    transition: transform 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94),
337	                box-shadow 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
338	  }
339	  .card-hover:hover {
340	    transform: translateY(-2px);
341	    box-shadow: 0 12px 40px -12px hsl(var(--foreground) / 0.08);
