343	
344	  /* ============ Stagger Children ============ */
345	  .stagger-children > * {
346	    opacity: 0;
347	    animation: stagger-fade 0.5s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
348	  }
349	  .stagger-children > *:nth-child(1) { animation-delay: 0.05s; }
350	  .stagger-children > *:nth-child(2) { animation-delay: 0.1s; }
351	  .stagger-children > *:nth-child(3) { animation-delay: 0.15s; }
352	  .stagger-children > *:nth-child(4) { animation-delay: 0.2s; }
353	  .stagger-children > *:nth-child(5) { animation-delay: 0.25s; }
354	  .stagger-children > *:nth-child(6) { animation-delay: 0.3s; }
355	
356	  @keyframes stagger-fade {
357	    from { opacity: 0; transform: translateY(8px); }
358	    to { opacity: 1; transform: translateY(0); }
359	  }
