1	import { motion } from "framer-motion";
2	import { useScrollReveal } from "@/hooks/use-scroll-reveal";
3	import { ReactNode } from "react";
4	
5	type AnimationVariant = "fade-up" | "fade-down" | "fade-left" | "fade-right" | "scale" | "blur";
6	
7	interface ScrollRevealProps {
8	  children: ReactNode;
9	  variant?: AnimationVariant;
10	  delay?: number;
11	  duration?: number;
12	  className?: string;
13	  once?: boolean;
14	}
15	
16	const variants: Record<AnimationVariant, { hidden: any; visible: any }> = {
17	  "fade-up": {
18	    hidden: { opacity: 0, y: 32, filter: "blur(4px)" },
19	    visible: { opacity: 1, y: 0, filter: "blur(0px)" },
20	  },
21	  "fade-down": {
22	    hidden: { opacity: 0, y: -24 },
23	    visible: { opacity: 1, y: 0 },
24	  },
25	  "fade-left": {
26	    hidden: { opacity: 0, x: -32 },
27	    visible: { opacity: 1, x: 0 },
28	  },
29	  "fade-right": {
30	    hidden: { opacity: 0, x: 32 },
31	    visible: { opacity: 1, x: 0 },
32	  },
33	  scale: {
34	    hidden: { opacity: 0, scale: 0.92 },
35	    visible: { opacity: 1, scale: 1 },
36	  },
37	  blur: {
38	    hidden: { opacity: 0, filter: "blur(12px)" },
39	    visible: { opacity: 1, filter: "blur(0px)" },
40	  },
41	};
42	
43	const ScrollReveal = ({
44	  children,
45	  variant = "fade-up",
46	  delay = 0,
47	  duration = 0.7,
48	  className = "",
49	  once = true,
50	}: ScrollRevealProps) => {
51	  const { ref, isVisible } = useScrollReveal({ once });
52	  const v = variants[variant];
53	
54	  return (
55	    <motion.div
56	      ref={ref}
57	      initial={v.hidden}
58	      animate={isVisible ? v.visible : v.hidden}
59	      transition={{
60	        duration,
61	        delay,
62	        ease: [0.25, 0.46, 0.45, 0.94], // Apple easeOut
63	      }}
64	      className={className}
65	    >
66	      {children}
67	    </motion.div>
68	  );
69	};
70	
71	export default ScrollReveal;
