1	import { useEffect, useRef, useState } from "react";
2	
3	interface UseScrollRevealOptions {
4	  threshold?: number;
5	  rootMargin?: string;
6	  once?: boolean;
7	}
8	
9	export const useScrollReveal = ({
10	  threshold = 0.15,
11	  rootMargin = "0px 0px -60px 0px",
12	  once = true,
13	}: UseScrollRevealOptions = {}) => {
14	  const ref = useRef<HTMLDivElement>(null);
15	  const [isVisible, setIsVisible] = useState(false);
16	
17	  useEffect(() => {
18	    const el = ref.current;
19	    if (!el) return;
20	
21	    const observer = new IntersectionObserver(
22	      ([entry]) => {
23	        if (entry.isIntersecting) {
24	          setIsVisible(true);
25	          if (once) observer.unobserve(el);
26	        } else if (!once) {
27	          setIsVisible(false);
28	        }
29	      },
30	      { threshold, rootMargin }
31	    );
32	
33	    observer.observe(el);
34	    return () => observer.disconnect();
35	  }, [threshold, rootMargin, once]);
36	
37	  return { ref, isVisible };
38	};
